function candidate(inputName, fallback) {
  if (inputName === undefined) return undefined;
  if (typeof inputName !== 'string') throw new TypeError('name must be a string');

  const fallbackSetting = fallback === undefined ? true : fallback;
  if (typeof fallbackSetting !== 'boolean' && typeof fallbackSetting !== 'string') {
    throw new TypeError('fallback must be a boolean or string');
  }

  const splitLast = value => String(value).split(/[\\/]/).pop();
  const hasNonLatin1 = value => /[^\x00-\xff]/.test(value);
  const canBeQuoted = value => /^[\x20-\x7e\x80-\xff]*$/.test(value);
  const needsPercentForm = value => /%[0-9a-fA-F]{2}/.test(value);

  if (typeof fallbackSetting === 'string' && hasNonLatin1(fallbackSetting)) {
    throw new TypeError('fallback must be ISO-8859-1 compatible');
  }

  const finalName = splitLast(inputName);
  let plainAlternative;

  if (typeof fallbackSetting === 'string') {
    plainAlternative = splitLast(fallbackSetting);
  } else if (fallbackSetting) {
    plainAlternative = finalName.replace(/[^\x00-\xff]/g, '?');
  }

  const hasDistinctFallback = typeof plainAlternative === 'string' && plainAlternative !== finalName;
  const safePlain = canBeQuoted(finalName);
  const result = {};

  if (hasDistinctFallback || !safePlain || needsPercentForm(finalName)) {
    result['filename*'] = finalName;
  }

  if (safePlain || hasDistinctFallback) {
    result.filename = hasDistinctFallback ? plainAlternative : finalName;
  }

  return result;
}
